var cors=require('cors')    // To handle CORS policy for cross origin resource sharing. It is a middle ware function that can be used to add the required headers, allow credentials and log requests 
const app = express() ;  
app.use(express.json())     // Middleware which parses incoming request bodies in a middleware before your handlers (route handlers) are executed for them . This is based on body-parser under the hood but provides more features like limiters, encoding types etc 
var db = require('./db')   // Database connection file. We use knex to interact with our database here as it's a popular choice and has good support in NodeJS environment for SQL queries (like insert/update)   
app.use(cookieParser());     // Middleware which parses the cookie sent by client, available on req object 
