app.use(cors())     // Enable CORS middleware to allow requests from different domains 
var bcrypt = require('bcryptjs');   // For hashing passwords securely - a popular choice in NodeJS environment for storing and comparing encrypted data (like when user is created or updated)   
app.use(express.urlencoded({ extended: false }));     // Middleware which parses the url-decoded body of an incoming request into req object 
var jwt_secret = process.env.JWT_SECRET;   // JWT secret from .env file (should be stored in environment variables)   
app.use(express.static('public'));     // Middleware to serve static files such as HTML, CSS etc., located under public folder 
